import React from 'react';
import { ArrowRight, Copy, Check } from 'lucide-react';
import { PromptData } from '../types';

interface PromptCardProps {
  prompt: PromptData;
  onClick: () => void;
  onQuickCopy: (e: React.MouseEvent, text: string) => void;
  isCopied: boolean;
}

const PromptCard: React.FC<PromptCardProps> = ({ prompt, onClick, onQuickCopy, isCopied }) => {
  return (
    <div 
      onClick={onClick}
      className="group bg-white rounded-xl border border-slate-200 p-5 cursor-pointer hover:shadow-md hover:border-blue-200 transition-all duration-200 flex flex-col h-full"
    >
      <div className="flex justify-between items-start mb-3">
        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-600 border border-slate-200">
          {prompt.format}
        </span>
        <button
          onClick={(e) => onQuickCopy(e, prompt.promptText)}
          className={`
            p-1.5 rounded-md transition-colors duration-200
            ${isCopied ? 'bg-green-100 text-green-700' : 'text-slate-400 hover:bg-slate-100 hover:text-slate-600'}
          `}
          title="Quick Copy"
        >
          {isCopied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
        </button>
      </div>

      <h3 className="font-bold text-slate-900 mb-2 leading-tight group-hover:text-blue-600 transition-colors">
        {prompt.title}
      </h3>

      <p className="text-sm text-slate-500 mb-4 line-clamp-2 flex-grow">
        {prompt.bestFor}
      </p>

      <div className="pt-4 border-t border-slate-50 flex items-center justify-between mt-auto">
        <span className="text-xs text-slate-400 font-medium">Click to view details</span>
        <div className="bg-slate-50 p-1.5 rounded-full group-hover:bg-blue-50 group-hover:text-blue-600 transition-colors">
          <ArrowRight className="w-4 h-4 text-slate-400 group-hover:text-blue-600" />
        </div>
      </div>
    </div>
  );
};

export default PromptCard;

import React, { useState, useEffect } from 'react';
import { X, Copy, Check, Info, Lightbulb } from 'lucide-react';
import { PromptData } from '../types';

interface PromptModalProps {
  prompt: PromptData | null;
  onClose: () => void;
}

const PromptModal: React.FC<PromptModalProps> = ({ prompt, onClose }) => {
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    setIsCopied(false);
  }, [prompt]);

  if (!prompt) return null;

  const handleCopy = () => {
    navigator.clipboard.writeText(prompt.promptText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-in fade-in zoom-in-95 duration-200">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-slate-100 bg-white sticky top-0 z-10">
          <div>
            <span className="text-xs font-semibold tracking-wider text-blue-600 uppercase mb-1 block">
              {prompt.format}
            </span>
            <h2 className="text-xl font-bold text-slate-900 leading-tight pr-8">
              {prompt.title}
            </h2>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors absolute top-4 right-4"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="overflow-y-auto p-6 space-y-6">

          {/* Main Prompt Area */}
          <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 relative group">
            <div className="absolute top-3 right-3">
              <button
                onClick={handleCopy}
                className={`
                  flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all shadow-sm
                  ${isCopied 
                    ? 'bg-green-600 text-white hover:bg-green-700' 
                    : 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200'}
                `}
              >
                {isCopied ? (
                  <>
                    <Check className="w-4 h-4" />
                    <span>Copied</span>
                  </>
                ) : (
                  <>
                    <Copy className="w-4 h-4" />
                    <span>Copy Prompt</span>
                  </>
                )}
              </button>
            </div>
            <pre className="whitespace-pre-wrap font-sans text-slate-800 text-sm leading-relaxed pt-8 sm:pt-0 sm:pr-24">
              {prompt.promptText}
            </pre>
          </div>

          {/* Details Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="bg-white border border-slate-100 rounded-lg p-4">
              <div className="flex items-center gap-2 mb-2 text-slate-900 font-semibold text-sm">
                <Info className="w-4 h-4 text-blue-500" />
                Best For
              </div>
              <p className="text-sm text-slate-600 leading-relaxed">
                {prompt.bestFor}
              </p>
            </div>

            <div className="bg-white border border-slate-100 rounded-lg p-4">
               <div className="flex items-center gap-2 mb-2 text-slate-900 font-semibold text-sm">
                <Lightbulb className="w-4 h-4 text-amber-500" />
                NotebookLM Tip
              </div>
              <p className="text-sm text-slate-600 leading-relaxed">
                {prompt.tip}
              </p>
            </div>
          </div>

           <div className="bg-blue-50 border border-blue-100 rounded-lg p-4">
              <h4 className="text-blue-900 font-semibold text-sm mb-1">Recommended Sources</h4>
              <p className="text-sm text-blue-700">
                {prompt.exampleSources}
              </p>
            </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

export default PromptModal;

import React, { useState, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import PromptCard from './components/PromptCard';
import PromptModal from './components/PromptModal';
import { PROMPTS, CATEGORIES } from './constants';
import { PromptData } from './types';
import { Search, Menu, Sparkles } from 'lucide-react';

function App() {
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedPrompt, setSelectedPrompt] = useState<PromptData | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  const activeCategoryData = CATEGORIES.find(c => c.id === activeCategory);

  const filteredPrompts = useMemo(() => {
    return PROMPTS.filter(prompt => {
      const matchesCategory = activeCategory === 'all' || prompt.categoryId === activeCategory;
      const matchesSearch = 
        prompt.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        prompt.bestFor.toLowerCase().includes(searchQuery.toLowerCase()) ||
        prompt.promptText.toLowerCase().includes(searchQuery.toLowerCase());

      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, searchQuery]);

  const handleQuickCopy = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900">
      <Sidebar 
        activeCategory={activeCategory} 
        onSelectCategory={setActiveCategory}
        isMobileOpen={isMobileSidebarOpen}
        setIsMobileOpen={setIsMobileSidebarOpen}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Top Header */}
        <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-4 flex-1">
            <button 
              className="md:hidden p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg"
              onClick={() => setIsMobileSidebarOpen(true)}
            >
              <Menu className="w-6 h-6" />
            </button>

            <div className="relative w-full max-w-md">
              <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search className="h-4 w-4 text-slate-400" />
              </div>
              <input
                type="text"
                className="block w-full pl-10 pr-3 py-2 border border-slate-200 rounded-xl leading-5 bg-slate-50 placeholder-slate-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm transition-all"
                placeholder="Search prompts (e.g. 'podcast', 'meeting', 'exam')..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>
          <div className="hidden sm:flex items-center gap-3">
             <a 
              href="https://notebooklm.google.com/" 
              target="_blank" 
              rel="noopener noreferrer"
              className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-blue-600 transition-colors"
             >
               Open NotebookLM
               <Sparkles className="w-4 h-4" />
             </a>
          </div>
        </header>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-8">
          <div className="max-w-6xl mx-auto">

            <div className="mb-8">
              <h2 className="text-2xl font-bold text-slate-900 mb-2">
                {activeCategoryData?.label}
              </h2>
              <p className="text-slate-500">
                {activeCategory === 'all' 
                  ? `${PROMPTS.length}+ context-engineered prompts ready to copy.` 
                  : activeCategoryData?.description}
              </p>
            </div>

            {filteredPrompts.length > 0 ? (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredPrompts.map((prompt) => (
                  <PromptCard 
                    key={prompt.id} 
                    prompt={prompt}
                    onClick={() => setSelectedPrompt(prompt)}
                    onQuickCopy={(e, text) => handleQuickCopy(e, text, prompt.id)}
                    isCopied={copiedId === prompt.id}
                  />
                ))}
              </div>
            ) : (
              <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
                <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-slate-900 mb-1">No prompts found</h3>
                <p className="text-slate-500">Try adjusting your search terms or category.</p>
                {activeCategory !== 'all' && (
                  <button 
                    onClick={() => setActiveCategory('all')}
                    className="mt-4 text-blue-600 font-medium hover:underline"
                  >
                    View all categories
                  </button>
                )}
              </div>
            )}

            <footer className="mt-12 text-center text-xs text-slate-400 pb-4">
              <p>Prompts designed using the R-I-S-E Framework (Role, Input, Stop, Example)</p>
            </footer>
          </div>
        </div>
      </main>

      <PromptModal 
        prompt={selectedPrompt} 
        onClose={() => setSelectedPrompt(null)} 
      />
    </div>
  );
}

export default App;

