import { Collaborator, Source, NoteVersion } from '../types';

const INITIAL_COLLABORATORS: Collaborator[] = [
  { id: 'current', name: 'You', role: 'owner', color: 'bg-blue-500', initials: 'ME', isActive: true },
  { id: '2', name: 'Sarah Chen', role: 'editor', color: 'bg-emerald-500', initials: 'SC', isActive: true },
  { id: '3', name: 'Mike Ross', role: 'viewer', color: 'bg-amber-500', initials: 'MR', isActive: false },
];

const INITIAL_SOURCES: Source[] = [
  { id: '1', type: 'paper', title: 'Attention Is All You Need', author: 'Vaswani et al.', year: '2017', url: 'https://arxiv.org/abs/1706.03762', citationId: 1 },
  { id: '2', type: 'website', title: 'Google NotebookLM Documentation', author: 'Google', year: '2024', url: 'https://notebooklm.google.com', citationId: 2 },
];

const DEFAULT_CONTENT = `# Project Alpha Strategy

We need to evaluate the core competencies of the new model architecture. According to recent studies [1], transformer models have revolutionized NLP tasks.

## Key Objectives
1. Analyze performance metrics
2. Optimize latency
3. Integrate with existing knowledge base [2]

Let's discuss the implementation details below...`;

const Workbench: React.FC = () => {
  // Initialize content from localStorage or default
  const [content, setContent] = useState<string>(() => {
    return localStorage.getItem('notebook_content') || DEFAULT_CONTENT;
  });

  // History State for Undo/Redo
  const [history, setHistory] = useState<string[]>([content]);
  const [historyIndex, setHistoryIndex] = useState(0);

  const [sources, setSources] = useState<Source[]>(INITIAL_SOURCES);
  const [collaborators, setCollaborators] = useState<Collaborator[]>(INITIAL_COLLABORATORS);
  const [isShareOpen, setIsShareOpen] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [versions, setVersions] = useState<NoteVersion[]>([]);
  const [lastSaved, setLastSaved] = useState('Just now');

  // Handle Content Change with History Debounce
  const handleContentChange = (newText: string) => {
    setContent(newText);

    // We only push to history if the user pauses or specific actions occur, 
    // but for this implementation, we'll update the current state immediately
    // and rely on a debounced effect to commit to history to avoid 1-char undos.
  };

  // Commit to history when user stops typing for 1 second
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      if (content !== history[historyIndex]) {
        const newHistory = history.slice(0, historyIndex + 1);
        newHistory.push(content);
        setHistory(newHistory);
        setHistoryIndex(newHistory.length - 1);
      }
    }, 1000);

    return () => clearTimeout(timeoutId);
  }, [content, historyIndex]); // eslint-disable-line react-hooks/exhaustive-deps

  // Undo/Redo Functions
  const handleUndo = () => {
    if (historyIndex > 0) {
      const newIndex = historyIndex - 1;
      setHistoryIndex(newIndex);
      setContent(history[newIndex]);
    }
  };

  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      const newIndex = historyIndex + 1;
      setHistoryIndex(newIndex);
      setContent(history[newIndex]);
    }
  };

  // Autosave to LocalStorage
  useEffect(() => {
    const saveInterval = setInterval(() => {
      localStorage.setItem('notebook_content', content);
      setLastSaved(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    }, 30000);

    // Initial save on unmount or change
    localStorage.setItem('notebook_content', content);

    return () => clearInterval(saveInterval);
  }, [content]);

  // Mock Versions
  useEffect(() => {
    setVersions([
      { id: 'v3', timestamp: 'Just now', author: 'You', content: content },
      { id: 'v2', timestamp: '10 mins ago', author: 'Sarah Chen', content: content.substring(0, Math.max(0, content.length - 50)) },
      { id: 'v1', timestamp: '1 hour ago', author: 'You', content: '# Initial Draft\n\nStarting thoughts...' },
    ]);
  }, [content]);

  const handleAddSource = (sourceData: Omit<Source, 'id'>) => {
    const newSource: Source = {
      ...sourceData,
      id: Math.random().toString(36).substr(2, 9),
    };
    setSources([...sources, newSource]);
  };

  const handleRemoveSource = (id: string) => {
    setSources(sources.filter(s => s.id !== id));
  };

  const handleCite = (source: Source) => {
    handleContentChange(content + ` [${source.citationId}]`);
  };

  const handleRoleUpdate = (id: string, role: Collaborator['role'] | 'remove') => {
    if (role === 'remove') {
      setCollaborators(prev => prev.filter(c => c.id !== id));
    } else {
      setCollaborators(prev => prev.map(c => c.id === id ? { ...c, role: role as any } : c));
    }
  };

  const restoreVersion = (version: NoteVersion) => {
    if (window.confirm('Restore this version? Current changes will be saved as a new version.')) {
      handleContentChange(version.content);
      setShowHistory(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-slate-50">
      {/* Top Bar */}
      <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0 z-20">
        <div className="flex items-center gap-4">
          <div>
            <h1 className="text-lg font-bold text-slate-800 flex items-center gap-2">
              Untitled Project 
              <span className="text-[10px] px-2 py-0.5 rounded-full bg-slate-100 text-slate-500 font-medium">Draft</span>
            </h1>
            <p className="text-xs text-slate-400 flex items-center gap-1">
              <Save className="w-3 h-3" /> Autosaved {lastSaved}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center -space-x-2">
            {collaborators.map(user => (
              <div 
                key={user.id} 
                className={`w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-xs text-white font-medium ${user.color}`}
                title={`${user.name} (${user.role})`}
              >
                {user.initials}
              </div>
            ))}
            <button 
              onClick={() => setIsShareOpen(true)}
              className="w-8 h-8 rounded-full border-2 border-dashed border-slate-300 flex items-center justify-center text-slate-400 hover:border-slate-400 hover:text-slate-600 bg-white transition-colors"
            >
              <Users className="w-4 h-4" />
            </button>
          </div>

          <div className="h-6 w-px bg-slate-200" />

          <div className="flex items-center gap-1">
             <button 
              onClick={handleUndo}
              disabled={historyIndex <= 0}
              className={`p-2 rounded-lg transition-colors ${historyIndex > 0 ? 'text-slate-600 hover:bg-slate-100' : 'text-slate-300 cursor-not-allowed'}`}
              title="Undo"
            >
              <Undo className="w-5 h-5" />
            </button>
            <button 
              onClick={handleRedo}
              disabled={historyIndex >= history.length - 1}
              className={`p-2 rounded-lg transition-colors ${historyIndex < history.length - 1 ? 'text-slate-600 hover:bg-slate-100' : 'text-slate-300 cursor-not-allowed'}`}
              title="Redo"
            >
              <Redo className="w-5 h-5" />
            </button>
          </div>

          <button 
            onClick={() => setShowHistory(!showHistory)}
            className={`p-2 rounded-lg transition-colors ${showHistory ? 'bg-slate-100 text-blue-600' : 'text-slate-500 hover:bg-slate-100'}`}
            title="Version History"
          >
            <Clock className="w-5 h-5" />
          </button>

          <button 
            onClick={() => setIsShareOpen(true)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
          >
            <Share2 className="w-4 h-4" />
            Share
          </button>
        </div>
      </header>

      {/* Main Workspace */}
      <div className="flex-1 flex overflow-hidden relative">

        {/* Editor */}
        <div className="flex-1 overflow-y-auto bg-white p-8 sm:p-12 shadow-inner">
          <div className="max-w-3xl mx-auto min-h-full">
            <Editor 
              content={content} 
              onChange={handleContentChange} 
              collaborators={collaborators}
            />
          </div>
        </div>

        {/* Citations Sidebar */}
        <CitationPanel 
          sources={sources}
          onAddSource={handleAddSource}
          onRemoveSource={handleRemoveSource}
          onCite={handleCite}
        />

        {/* Version History Overlay */}
        {showHistory && (
          <div className="absolute right-0 top-0 bottom-0 w-80 bg-slate-50 border-l border-slate-200 shadow-xl transform transition-transform z-30 flex flex-col">
            <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-white">
              <h3 className="font-bold text-slate-800">Version History</h3>
              <button onClick={() => setShowHistory(false)} className="text-slate-400 hover:text-slate-600">
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <div className="overflow-y-auto p-4 space-y-4">
              {versions.map((version) => (
                <div 
                  key={version.id} 
                  className="bg-white p-3 rounded-lg border border-slate-200 hover:border-blue-300 cursor-pointer group transition-all"
                  onClick={() => restoreVersion(version)}
                >
                  <div className="flex justify-between items-start mb-1">
                    <span className="text-xs font-semibold text-slate-700">{version.timestamp}</span>
                    <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity">Restore</span>
                  </div>
                  <div className="flex items-center gap-2 mb-2">
                    <div className="w-4 h-4 rounded-full bg-blue-500 text-[8px] text-white flex items-center justify-center">
                      {version.author.charAt(0)}
                    </div>
                    <span className="text-xs text-slate-500">{version.author}</span>
                  </div>
                  <p className="text-[10px] text-slate-400 line-clamp-2 font-mono bg-slate-50 p-1 rounded">
                    {version.content}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <ShareDialog 
        isOpen={isShareOpen} 
        onClose={() => setIsShareOpen(false)}
        collaborators={collaborators}
        onUpdateRole={handleRoleUpdate}
      />
    </div>
  );
};

export default Workbench;

import React, { useRef, useEffect, useState } from 'react';
import { Collaborator } from '../types';
import { Eye, Edit3, Type, List, Bold, Italic } from 'lucide-react';

interface EditorProps {
  content: string;
  onChange: (text: string) => void;
  collaborators: Collaborator[];
}

const Editor: React.FC<EditorProps> = ({ content, onChange, collaborators }) => {
  const [mode, setMode] = useState<'write' | 'preview'>('write');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current && mode === 'write') {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [content, mode]);

  // Simulated active cursors for other users
  const activeCollaborators = collaborators.filter(c => c.isActive && c.id !== 'current');

  // Simple markdown parser for preview
  const renderMarkdown = (text: string) => {
    let html = text
      // Headers
      .replace(/^# (.*$)/gm, '<h1 class="text-3xl font-bold mb-4 mt-6">$1</h1>')
      .replace(/^## (.*$)/gm, '<h2 class="text-2xl font-semibold mb-3 mt-5">$1</h2>')
      .replace(/^### (.*$)/gm, '<h3 class="text-xl font-medium mb-2 mt-4">$1</h3>')
      // Bold/Italic
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      // Lists
      .replace(/^- (.*$)/gm, '<li class="ml-4 list-disc mb-1">$1</li>')
      .replace(/^\d+\. (.*$)/gm, '<li class="ml-4 list-decimal mb-1">$1</li>')
      // Blockquotes
      .replace(/^> (.*$)/gm, '<blockquote class="border-l-4 border-slate-300 pl-4 italic my-4 text-slate-600">$1</blockquote>')
      // Links
      .replace(/\[(.*?)\]\((.*?)\)/g, '<a href="$2" class="text-blue-600 hover:underline" target="_blank">$1</a>')
      // Citations (Special case for this app)
      .replace(/\[(\d+)\]/g, '<sup class="text-blue-600 font-bold ml-0.5 cursor-pointer">[$1]</sup>')
      // Line breaks
      .replace(/\n/g, '<br />');

    return { __html: html };
  };

  return (
    <div className="relative font-sans text-sm sm:text-base leading-relaxed flex flex-col h-full">
      {/* Editor Toolbar */}
      <div className="sticky top-0 bg-white/95 backdrop-blur z-20 border-b border-slate-100 pb-4 mb-4 flex items-center justify-between">
        <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-lg">
          <button
            onClick={() => setMode('write')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
              mode === 'write' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <Edit3 className="w-3.5 h-3.5" />
            Write
          </button>
          <button
            onClick={() => setMode('preview')}
            className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
              mode === 'preview' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            <Eye className="w-3.5 h-3.5" />
            Preview
          </button>
        </div>

        {mode === 'write' && (
          <div className="flex items-center gap-1 text-slate-400">
            <span className="text-[10px] uppercase font-bold tracking-wider mr-2">Format</span>
            <Bold className="w-4 h-4" />
            <Italic className="w-4 h-4" />
            <List className="w-4 h-4" />
            <Type className="w-4 h-4" />
          </div>
        )}
      </div>

      {/* Editor Content */}
      <div className="flex-1 relative min-h-[50vh]">
        {mode === 'write' ? (
          <>
            <textarea
              ref={textareaRef}
              value={content}
              onChange={(e) => onChange(e.target.value)}
              className="w-full h-full bg-transparent resize-none focus:outline-none text-slate-800 placeholder-slate-300 font-mono"
              placeholder="Start typing your prompt or notes here... (Markdown supported)"
              spellCheck={false}
            />
            {/* Fake cursors overlay (only visible in write mode) */}
            {activeCollaborators.map((user, idx) => (
              <div 
                key={user.id}
                className="absolute pointer-events-none flex flex-col items-start z-10 animate-pulse transition-all duration-1000"
                style={{
                  // Random positions for demo purposes.
                  top: `${100 + (idx * 60)}px`,
                  left: `${20 + (idx * 150)}%`
                }}
              >
                <div className={`h-5 w-0.5 ${user.color}`}></div>
                <div className={`px-1.5 py-0.5 text-[10px] font-bold text-white rounded-br rounded-bl rounded-tr ${user.color}`}>
                  {user.name}
                </div>
              </div>
            ))}
          </>
        ) : (
          <div 
            className="prose prose-slate max-w-none prose-headings:text-slate-900 prose-p:text-slate-700 prose-a:text-blue-600 prose-sm sm:prose-base"
            dangerouslySetInnerHTML={renderMarkdown(content)}
          />
        )}
      </div>
    </div>
  );
};

export default Editor;

import React, { useState } from 'react';
import { X, Wand2, Copy, Check, RefreshCw } from 'lucide-react';
import { CATEGORIES } from '../constants';

interface PromptGeneratorProps {
  isOpen: boolean;
  onClose: () => void;
}

const PromptGenerator: React.FC<PromptGeneratorProps> = ({ isOpen, onClose }) => {
  const [topic, setTopic] = useState('');
  const [format, setFormat] = useState('Audio Overview');
  const [audience, setAudience] = useState('General Audience');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPrompt, setGeneratedPrompt] = useState('');
  const [isCopied, setIsCopied] = useState(false);

  if (!isOpen) return null;

  const handleGenerate = (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);

    // Simulate AI thinking time
    setTimeout(() => {
      const prompt = `Act as an expert content creator specializing in ${format} for ${audience}.

Given the uploaded source materials related to ${topic}, analyze the key information, themes, and data points.

Stop at the provided context. Do not introduce external information or hallucinations outside of the source text.

Deliver a ${format} that is strictly based on the source text, structured logically, and optimized for ${audience}.`;

      setGeneratedPrompt(prompt);
      setIsGenerating(false);
    }, 800);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(generatedPrompt);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const handleReset = () => {
    setGeneratedPrompt('');
    setIsCopied(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden flex flex-col animate-in fade-in zoom-in-95 duration-200 border border-slate-100">
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-slate-100 bg-gradient-to-r from-purple-50 to-white">
          <div className="flex items-center gap-2">
            <div className="bg-purple-100 p-2 rounded-lg text-purple-600">
              <Wand2 className="w-5 h-5" />
            </div>
            <h2 className="text-lg font-bold text-slate-900">Prompt Generator</h2>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6">
          {!generatedPrompt ? (
            <form onSubmit={handleGenerate} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Topic or Source Material
                </label>
                <input
                  type="text"
                  required
                  placeholder="e.g., Quarterly Financial Report, The Great Gatsby"
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent transition-all"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Format
                  </label>
                  <select
                    value={format}
                    onChange={(e) => setFormat(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent bg-white"
                  >
                    {CATEGORIES.filter(c => c.id !== 'all').map(c => (
                      <option key={c.id} value={c.label}>{c.label}</option>
                    ))}
                    <option value="Custom Format">Custom Format</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Target Audience
                  </label>
                  <input
                    type="text"
                    placeholder="e.g., Beginners, Executives"
                    value={audience}
                    onChange={(e) => setAudience(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  />
                </div>
              </div>

              <div className="pt-2">
                <button
                  type="submit"
                  disabled={!topic || isGenerating}
                  className={`
                    w-full flex items-center justify-center gap-2 py-2.5 rounded-lg text-white font-medium transition-all
                    ${!topic || isGenerating 
                      ? 'bg-purple-300 cursor-not-allowed' 
                      : 'bg-purple-600 hover:bg-purple-700 shadow-md hover:shadow-lg'}
                  `}
                >
                  {isGenerating ? (
                    <>
                      <RefreshCw className="w-4 h-4 animate-spin" />
                      Generating...
                    </>
                  ) : (
                    <>
                      <Wand2 className="w-4 h-4" />
                      Generate Prompt
                    </>
                  )}
                </button>
              </div>

              <p className="text-center text-xs text-slate-400 mt-2">
                Uses the R-I-S-E framework to structure your prompt automatically.
              </p>
            </form>
          ) : (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">
              <div className="bg-purple-50 border border-purple-100 rounded-xl p-4 relative">
                <div className="absolute top-3 right-3 flex gap-2">
                  <button
                    onClick={handleCopy}
                    className={`
                      p-1.5 rounded-md transition-all
                      ${isCopied ? 'bg-green-100 text-green-700' : 'bg-white text-slate-400 hover:text-purple-600 shadow-sm'}
                    `}
                    title="Copy to clipboard"
                  >
                    {isCopied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
                <h3 className="text-xs font-bold text-purple-800 uppercase tracking-wider mb-2">Generated Prompt</h3>
                <pre className="whitespace-pre-wrap font-sans text-slate-800 text-sm leading-relaxed pr-8">
                  {generatedPrompt}
                </pre>
              </div>

              <div className="flex gap-3">
                <button
                  onClick={handleReset}
                  className="flex-1 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm font-medium transition-colors"
                >
                  Create Another
                </button>
                <button
                  onClick={() => {
                    handleCopy();
                    onClose();
                  }}
                  className="flex-1 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium transition-colors shadow-sm"
                >
                  Copy & Close
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default PromptGenerator;

