interface PromptModalProps {
  prompt: PromptData | null;
  collections?: Collection[];
  onUpdatePrompt?: (prompt: PromptData) => void;
  onClose: () => void;
}

const PromptModal: React.FC<PromptModalProps> = ({ prompt, collections = [], onUpdatePrompt, onClose }) => {
  const [isCopied, setIsCopied] = useState(false);
  const [tags, setTags] = useState<string>('');
  const [collectionId, setCollectionId] = useState<string>('');
  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    setIsCopied(false);
    if (prompt) {
      setTags(prompt.tags ? prompt.tags.join(', ') : '');
      setCollectionId(prompt.collectionId || '');
      // Only show editing interface by default if it's already a custom prompt? 
      // For now, let's keep it view-only unless user decides to organize
      setIsEditing(false);
    }
  }, [prompt]);

  if (!prompt) return null;

  const handleCopy = () => {
    navigator.clipboard.writeText(prompt.promptText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const handleSaveOrganization = () => {
    if (onUpdatePrompt) {
      const parsedTags = tags.split(',').map(t => t.trim()).filter(t => t.length > 0);
      onUpdatePrompt({
        ...prompt,
        tags: parsedTags,
        collectionId: collectionId || undefined
      });
      setIsEditing(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
