                  <form onSubmit={handleSubmitCollection} className="px-3 mb-2">
                    <input
                      type="text"
                      autoFocus
                      placeholder="Name..."
                      className="w-full text-xs px-2 py-1.5 border border-slate-300 rounded focus:border-blue-500 focus:outline-none"
                      value={newCollectionName}
                      onChange={(e) => setNewCollectionName(e.target.value)}
                      onBlur={() => !newCollectionName && setIsCreatingCollection(false)}
                    />
                  </form>
                )}

                {collections.map((collection) => (
                   <div 
                      key={collection.id} 
                      className={`
                        group flex items-center justify-between pr-2 rounded-lg transition-all
                        ${dragOverId === collection.id ? 'bg-blue-50 ring-2 ring-blue-200 scale-[1.02]' : ''}
                      `}
                      onDragOver={(e) => handleDragOver(e, collection.id)}
                      onDragLeave={handleDragLeave}
                      onDrop={(e) => handleDrop(e, collection.id)}
                   >
                     <button
                      onClick={() => {
                        onSelectCategory(collection.id);
                        setIsMobileOpen(false);
                      }}
                      className={`
                        flex-1 flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-all duration-200 text-left truncate
                        ${activeCategory === collection.id 
                          ? 'bg-slate-100 text-slate-900' 
                          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}
                      `}
                    >
                      <Folder className={`w-4 h-4 flex-shrink-0 ${activeCategory === collection.id ? 'fill-blue-100 text-blue-600' : 'fill-slate-50 text-slate-400'}`} />
                      <span className="truncate">{collection.name}</span>
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        onDeleteCollection(collection.id);
                      }}
                      className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded transition-all"
                      title="Delete Collection"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                   </div>
                ))}
              </div>

              <p className="px-3 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 mt-6">Categories</p>
              {CATEGORIES.filter(c => c.id !== 'all').map((category) => {
                const isActive = activeCategory === category.id;
                return (
                  <button
                    key={category.id}
                    onClick={() => {
                      onSelectCategory(category.id);
                      setIsMobileOpen(false);
                    }}
                    className={`
                      w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200
                      ${isActive 
                        ? 'bg-slate-100 text-slate-900' 
                        : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}
                    `}
                  >
                    {getIcon(category.iconName as IconName, `w-4 h-4 ${isActive ? 'text-slate-600' : 'text-slate-400'}`)}
                    {category.label}
                  </button>
                );
              })}
            </div>
          )}

          {currentView === 'workbench' && (
             <div className="flex-1 overflow-y-auto scrollbar-hide space-y-4 px-3 animate-in fade-in slide-in-from-left-4 duration-300">
               <div className="bg-purple-50 rounded-lg p-3 border border-purple-100">
                 <h4 className="text-xs font-bold text-purple-800 mb-1">Collaborative Mode</h4>
                 <p className="text-xs text-purple-600 leading-relaxed mb-3">
                   Mock environment to test prompts with simulated real-time editing and citation tools.
                 </p>

                 <div className="text-[10px] text-purple-700 font-medium bg-purple-100/50 p-2 rounded border border-purple-200 space-y-1">
                   <p className="font-bold text-purple-800">Shortcuts</p>
                   <div className="flex justify-between"><span>Save</span> <span>Cmd + S</span></div>
                   <div className="flex justify-between"><span>Undo</span> <span>Cmd + Z</span></div>
                   <div className="flex justify-between"><span>Redo</span> <span>Cmd + Shift + Z</span></div>
                   <div className="flex justify-between"><span>Toggle Preview</span> <span>Cmd + I</span></div>
                 </div>
               </div>
             </div>
          )}

          <div className="mt-8 pt-6 border-t border-slate-100">
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <h3 className="font-semibold text-slate-800 text-sm mb-1">R-I-S-E Framework</h3>
              <ul className="text-xs text-slate-500 space-y-1">
                <li><strong className="text-slate-700">R</strong>ole: Who AI acts as</li>
                <li><strong className="text-slate-700">I</strong>nput: Sources to use</li>
                <li><strong className="text-slate-700">S</strong>top: Boundaries</li>
                <li><strong className="text-slate-700">E</strong>xample: Output format</li>
              </ul>
            </div>
          </div>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import PromptCard from './components/PromptCard';
import PromptModal from './components/PromptModal';
import Workbench from './components/Workbench';
import PromptGenerator from './components/PromptGenerator';
import { PROMPTS, CATEGORIES } from './constants';
import { PromptData, Collection } from './types';
import { Search, Menu, Sparkles } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<'library' | 'workbench'>('library');
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedPrompt, setSelectedPrompt] = useState<PromptData | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [isGeneratorOpen, setIsGeneratorOpen] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Load saved prompts from localStorage
  const [savedPrompts, setSavedPrompts] = useState<PromptData[]>(() => {
    const saved = localStorage.getItem('notebook_saved_prompts');
    return saved ? JSON.parse(saved) : [];
  });

  // Load collections from localStorage
  const [collections, setCollections] = useState<Collection[]>(() => {
    const saved = localStorage.getItem('notebook_collections');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist saved prompts
  useEffect(() => {
    localStorage.setItem('notebook_saved_prompts', JSON.stringify(savedPrompts));
  }, [savedPrompts]);

  // Persist collections
  useEffect(() => {
    localStorage.setItem('notebook_collections', JSON.stringify(collections));
  }, [collections]);

  // Determine header text based on selection
  const activeCollection = collections.find(c => c.id === activeCategory);

  const activeCategoryData = useMemo(() => {
    if (activeCategory === 'saved') {
      return { id: 'saved', label: 'My Saved Templates', description: 'Your custom generated prompts' };
    }
    if (activeCollection) {
      return { id: activeCollection.id, label: activeCollection.name, description: 'Custom Collection' };
    }
    return CATEGORIES.find(c => c.id === activeCategory);
  }, [activeCategory, activeCollection]);

  const allPrompts = useMemo(() => {
    return [...savedPrompts, ...PROMPTS];
  }, [savedPrompts]);

  const filteredPrompts = useMemo(() => {
    return allPrompts.filter(prompt => {
      let matchesCategory = false;

      if (activeCategory === 'all') {
        matchesCategory = true;
      } else if (activeCategory === 'saved') {
        matchesCategory = prompt.categoryId === 'saved';
      } else if (activeCollection) {
        matchesCategory = prompt.collectionId === activeCategory;
      } else {
        matchesCategory = prompt.categoryId === activeCategory;
      }

      const matchesSearch = 
        prompt.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        prompt.bestFor.toLowerCase().includes(searchQuery.toLowerCase()) ||
        prompt.promptText.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (prompt.tags && prompt.tags.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase())));

      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, activeCollection, searchQuery, allPrompts]);

  const handleQuickCopy = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleSaveCustomPrompt = (prompt: PromptData) => {
    setSavedPrompts(prev => [prompt, ...prev]);
    // Switch to the collection if one was assigned, otherwise saved view
    if (prompt.collectionId) {
      setActiveCategory(prompt.collectionId);
    } else {
      setActiveCategory('saved');
    }
    setCurrentView('library');
  };

  const handleUpdatePrompt = (updatedPrompt: PromptData) => {
    // Check if it's a saved prompt or a built-in one
    const isSaved = savedPrompts.some(p => p.id === updatedPrompt.id);

    if (isSaved) {
      setSavedPrompts(prev => prev.map(p => p.id === updatedPrompt.id ? updatedPrompt : p));
    } else {
      // If user edits a built-in prompt (like adding a tag), we save it as a new copy in their library 
      // to avoid mutating the constant data, or we could just locally override.
      const newSavedPrompt = { ...updatedPrompt, categoryId: 'saved' };
      setSavedPrompts(prev => [newSavedPrompt, ...prev]);
    }
    setSelectedPrompt(updatedPrompt);
  };

  const handleCreateCollection = (name: string) => {
    const newCollection: Collection = {
      id: `col_${Date.now()}`,
      name,
      color: 'bg-blue-500', // Default color, could be random
      createdAt: Date.now()
    };
    setCollections(prev => [...prev, newCollection]);
    setActiveCategory(newCollection.id);
  };

  const handleDeleteCollection = (id: string) => {
    if (confirm('Are you sure you want to delete this collection? Prompts inside will remain in "Saved Templates".')) {
      setCollections(prev => prev.filter(c => c.id !== id));
      // Remove collectionId from prompts in this collection
      setSavedPrompts(prev => prev.map(p => p.collectionId === id ? { ...p, collectionId: undefined } : p));
      setActiveCategory('saved');
    }
  };

  // Drag and Drop Logic
  const handleMovePrompt = (promptId: string, targetCollectionId: string) => {
    const promptToMove = allPrompts.find(p => p.id === promptId);
    if (!promptToMove) return;

    const isAlreadySaved = savedPrompts.some(p => p.id === promptId);

    if (isAlreadySaved) {
       // Update existing saved prompt
       setSavedPrompts(prev => prev.map(p => 
         p.id === promptId ? { ...p, collectionId: targetCollectionId } : p
       ));
    } else {
       // Create a copy of the built-in prompt in the user's library
       const newPrompt = { 
         ...promptToMove, 
         categoryId: 'saved',
         collectionId: targetCollectionId,
         // Ensure unique ID if cloning built-in to avoid conflicts if they drag it multiple times
         id: `saved_${promptToMove.id}_${Date.now()}` 
       };
       setSavedPrompts(prev => [...prev, newPrompt]);
    }
    // Optional: Switch view to target collection to show success
    // setActiveCategory(targetCollectionId);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900 overflow-hidden">
      <Sidebar 
        activeCategory={activeCategory} 
        onSelectCategory={setActiveCategory}
        collections={collections}
        onCreateCollection={handleCreateCollection}
        onDeleteCollection={handleDeleteCollection}
        isMobileOpen={isMobileSidebarOpen}
        setIsMobileOpen={setIsMobileSidebarOpen}
        currentView={currentView}
        onChangeView={setCurrentView}
        onOpenGenerator={() => setIsGeneratorOpen(true)}
        onMovePrompt={handleMovePrompt}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden relative w-full">
        {/* Mobile Menu Button - Floating for Workbench view */}
        <button 
          className="md:hidden absolute top-4 left-4 z-40 p-2 bg-white/80 backdrop-blur shadow-sm border border-slate-200 rounded-lg text-slate-500"
          onClick={() => setIsMobileSidebarOpen(true)}
        >
          <Menu className="w-5 h-5" />
        </button>

        {currentView === 'library' ? (
          <>
            {/* Top Header */}
            <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0 pl-16 md:pl-6">
              <div className="flex items-center gap-4 flex-1">
                <div className="relative w-full max-w-md">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Search className="h-4 w-4 text-slate-400" />
                  </div>
                  <input
                    type="text"
                    className="block w-full pl-10 pr-3 py-2 border border-slate-200 rounded-xl leading-5 bg-slate-50 placeholder-slate-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm transition-all"
                    placeholder="Search prompts by title, tag, or content..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
              </div>
              <div className="hidden sm:flex items-center gap-3">
                 <a 
                  href="https://notebooklm.google.com/" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-blue-600 transition-colors"
                 >
                   Open NotebookLM
                   <Sparkles className="w-4 h-4" />
                 </a>
              </div>
            </header>

            {/* Scrollable Content */}
            <div className="flex-1 overflow-y-auto p-6 md:p-8">
              <div className="max-w-6xl mx-auto">

                <div className="mb-8">
                  <h2 className="text-2xl font-bold text-slate-900 mb-2">
                    {activeCategoryData?.label || 'Unknown Category'}
                  </h2>
                  <p className="text-slate-500">
                    {activeCategory === 'all' 
                      ? `${allPrompts.length}+ context-engineered prompts ready to copy.` 
                      : activeCategoryData?.description}
                  </p>
                </div>

                {filteredPrompts.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredPrompts.map((prompt) => (
                      <PromptCard 
                        key={prompt.id} 
                        prompt={prompt}
                        onClick={() => setSelectedPrompt(prompt)}
                        onQuickCopy={(e, text) => handleQuickCopy(e, text, prompt.id)}
                        isCopied={copiedId === prompt.id}
                      />
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
                    <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                    <h3 className="text-lg font-medium text-slate-900 mb-1">No prompts found</h3>
                    <p className="text-slate-500">Try adjusting your search terms or category.</p>
                    {activeCategory !== 'all' && (
                      <button 
                        onClick={() => setActiveCategory('all')}
                        className="mt-4 text-blue-600 font-medium hover:underline"
                      >
                        View all categories
                      </button>
                    )}
                  </div>
                )}

                <footer className="mt-12 text-center text-xs text-slate-400 pb-4">
                  <p>Prompts designed using the R-I-S-E Framework (Role, Input, Stop, Example)</p>
                </footer>
              </div>
            </div>

            <PromptModal 
              prompt={selectedPrompt} 
              collections={collections}
              onUpdatePrompt={handleUpdatePrompt}
              onClose={() => setSelectedPrompt(null)} 
            />
          </>
        ) : (
          <Workbench />
        )}

        {/* Global Prompt Generator Modal */}
        <PromptGenerator 
          isOpen={isGeneratorOpen} 
          collections={collections}
          onClose={() => setIsGeneratorOpen(false)} 
          onSave={handleSaveCustomPrompt}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { X, ChevronRight, Check, Book, Layers, Sparkles, BrainCircuit } from 'lucide-react';

interface TutorialOverlayProps {
  isOpen: boolean;
  onClose: () => void;
}

const TutorialOverlay: React.FC<TutorialOverlayProps> = ({ isOpen, onClose }) => {
  const [step, setStep] = useState(0);

  if (!isOpen) return null;

  const steps = [
    {
      icon: <Book className="w-8 h-8 text-blue-500" />,
      title: "Welcome to Prompt Lib",
      description: "Access 200+ curated prompts designed specifically for NotebookLM. Optimized using the R-I-S-E framework to get the best results."
    },
    {
      icon: <Layers className="w-8 h-8 text-indigo-500" />,
      title: "Collections & Tags",
      description: "Organize your workflow. Create custom collections in the sidebar and drag-and-drop prompts to save them. Add tags to find things faster."
    },
    {
      icon: <Sparkles className="w-8 h-8 text-purple-500" />,
      title: "Workbench Mode",
      description: "Switch to the Workbench to edit prompts, manage citations, and simulate collaborative sessions before using them in NotebookLM."
    },
    {
      icon: <BrainCircuit className="w-8 h-8 text-emerald-500" />,
      title: "Smart Generation",
      description: "Can't find what you need? Use the Prompt Generator to create custom templates tailored to your specific topic and audience."
    }
  ];

  const handleNext = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    } else {
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/70 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-300">
        {/* Progress Bar */}
        <div className="h-1 bg-slate-100 w-full">
          <div 
            className="h-full bg-blue-500 transition-all duration-300 ease-out"
            style={{ width: `${((step + 1) / steps.length) * 100}%` }}
          />
        </div>

        <button 
          onClick={onClose}
          className="absolute top-4 right-4 p-2 text-slate-300 hover:text-slate-500 hover:bg-slate-100 rounded-full transition-colors"
        >
          <X className="w-5 h-5" />
        </button>

        <div className="p-8 text-center">
          <div className="mx-auto w-16 h-16 bg-slate-50 rounded-2xl flex items-center justify-center mb-6 shadow-sm border border-slate-100">
            {steps[step].icon}
          </div>

          <h2 className="text-2xl font-bold text-slate-900 mb-3">
            {steps[step].title}
          </h2>

          <p className="text-slate-500 leading-relaxed mb-8">
            {steps[step].description}
          </p>

          <div className="flex items-center gap-3">
            <div className="flex gap-1.5 flex-1 justify-center">
              {steps.map((_, i) => (
                <div 
                  key={i}
                  className={`w-2 h-2 rounded-full transition-colors duration-300 ${i === step ? 'bg-slate-800' : 'bg-slate-200'}`}
                />
              ))}
            </div>

            <button
              onClick={handleNext}
              className="flex items-center gap-2 bg-slate-900 text-white px-6 py-2.5 rounded-xl font-medium hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 hover:shadow-slate-300 ml-auto"
            >
              {step === steps.length - 1 ? (
                <>Get Started <Check className="w-4 h-4" /></>
              ) : (
                <>Next <ChevronRight className="w-4 h-4" /></>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TutorialOverlay;

import React, { useState } from 'react';
import { 
  Headphones, 
  Video, 
  BrainCircuit, 
  FileText, 
  Layers, 
  HelpCircle, 
  PieChart, 
  Presentation, 
  Table, 
  LayoutGrid,
  Sparkles,
  X,
  Wand2,
  Bookmark,
  Folder,
  Plus,
  Trash2
} from 'lucide-react';
import { CATEGORIES } from '../constants';
import { IconName, Collection } from '../types';

interface SidebarProps {
  activeCategory: string;
  onSelectCategory: (id: string) => void;
  collections: Collection[];
  onCreateCollection: (name: string) => void;
  onDeleteCollection: (id: string) => void;
  isMobileOpen: boolean;
  setIsMobileOpen: (isOpen: boolean) => void;
  currentView: 'library' | 'workbench';
  onChangeView: (view: 'library' | 'workbench') => void;
  onOpenGenerator: () => void;
  onMovePrompt?: (promptId: string, collectionId: string) => void;
}

const getIcon = (name: IconName, className: string) => {
  const icons: Record<IconName, React.ReactNode> = {
    Headphones: <Headphones className={className} />,
    Video: <Video className={className} />,
    BrainCircuit: <BrainCircuit className={className} />,
    FileText: <FileText className={className} />,
    Layers: <Layers className={className} />,
    HelpCircle: <HelpCircle className={className} />,
    PieChart: <PieChart className={className} />,
    Presentation: <Presentation className={className} />,
    Table: <Table className={className} />,
    All: <LayoutGrid className={className} />,
    Sparkles: <Sparkles className={className} />,
  };
  return icons[name] || <LayoutGrid className={className} />;
};

const Sidebar: React.FC<SidebarProps> = ({ 
  activeCategory, 
  onSelectCategory, 
  collections,
  onCreateCollection,
  onDeleteCollection,
  isMobileOpen, 
  setIsMobileOpen,
  currentView,
  onChangeView,
  onOpenGenerator,
  onMovePrompt
}) => {
  const [isCreatingCollection, setIsCreatingCollection] = useState(false);
  const [newCollectionName, setNewCollectionName] = useState('');
  const [dragOverId, setDragOverId] = useState<string | null>(null);

  // Badge dismissal state
  const [showNewBadge, setShowNewBadge] = useState(() => {
    return !localStorage.getItem('workbench_badge_dismissed');
  });

  const handleSubmitCollection = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCollectionName.trim()) {
      onCreateCollection(newCollectionName.trim());
      setNewCollectionName('');
      setIsCreatingCollection(false);
    }
  };

  const handleDragOver = (e: React.DragEvent, collectionId: string) => {
    e.preventDefault();
    setDragOverId(collectionId);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    setDragOverId(null);
  };

  const handleDrop = (e: React.DragEvent, collectionId: string) => {
    e.preventDefault();
    setDragOverId(null);
    const promptId = e.dataTransfer.getData('text/plain');
    if (promptId && onMovePrompt) {
      onMovePrompt(promptId, collectionId);
    }
  };

  const dismissBadge = (e: React.MouseEvent) => {
    e.stopPropagation();
    setShowNewBadge(false);
    localStorage.setItem('workbench_badge_dismissed', 'true');
  };

  return (
    <>
      {/* Mobile Overlay */}
      <div 
        className={`fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 md:hidden transition-opacity duration-300 ease-in-out ${
          isMobileOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        onClick={() => setIsMobileOpen(false)}
      />

      {/* Sidebar Content */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 cubic-bezier(0.4, 0, 0.2, 1) shadow-2xl md:shadow-none
        md:translate-x-0 md:static md:w-64 md:block
        ${isMobileOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <div 
              className="flex items-center gap-2 cursor-pointer group" 
              onClick={() => { 
                onChangeView('library'); 
                setIsMobileOpen(false); 
              }}
            >
              <div className="bg-gradient-to-br from-blue-500 to-indigo-600 p-2 rounded-lg group-hover:shadow-md transition-all duration-200">
                <BrainCircuit className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="font-bold text-xl text-slate-800 leading-tight">Prompt Lib</h1>
                <p className="text-xs text-slate-500 font-medium">for NotebookLM</p>
              </div>
            </div>

            {/* Close button for mobile */}
            <button 
              onClick={() => setIsMobileOpen(false)}
              className="md:hidden p-2 text-slate-400 hover:bg-slate-100 hover:text-slate-600 rounded-lg transition-colors"
              aria-label="Close sidebar"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="space-y-1 mb-8">
            <button
              onClick={() => {
                onChangeView('library');
                setIsMobileOpen(false);
              }}
              className={`
