import React, { useState, useMemo, useEffect, useRef } from 'react';
import Sidebar from './components/Sidebar';
import PromptCard from './components/PromptCard';
import PromptModal from './components/PromptModal';
import Workbench from './components/Workbench';
import PromptGenerator from './components/PromptGenerator';
import TutorialOverlay from './components/TutorialOverlay';
import { PROMPTS, CATEGORIES } from './constants';
import { PromptData, Collection } from './types';
import { Search, Menu, Sparkles, Filter, ChevronDown } from 'lucide-react';

function App() {
  const [currentView, setCurrentView] = useState<'library' | 'workbench'>('library');
  const [activeCategory, setActiveCategory] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedFormat, setSelectedFormat] = useState('All');
  const [showSearchSuggestions, setShowSearchSuggestions] = useState(false);

  const [selectedPrompt, setSelectedPrompt] = useState<PromptData | null>(null);
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [isGeneratorOpen, setIsGeneratorOpen] = useState(false);
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const searchContainerRef = useRef<HTMLDivElement>(null);

  // Tutorial State
  const [showTutorial, setShowTutorial] = useState(() => {
    return !localStorage.getItem('tutorial_completed');
  });

  // Load saved prompts from localStorage
  const [savedPrompts, setSavedPrompts] = useState<PromptData[]>(() => {
    const saved = localStorage.getItem('notebook_saved_prompts');
    return saved ? JSON.parse(saved) : [];
  });

  // Load collections from localStorage
  const [collections, setCollections] = useState<Collection[]>(() => {
    const saved = localStorage.getItem('notebook_collections');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist saved prompts
  useEffect(() => {
    localStorage.setItem('notebook_saved_prompts', JSON.stringify(savedPrompts));
  }, [savedPrompts]);

  // Persist collections
  useEffect(() => {
    localStorage.setItem('notebook_collections', JSON.stringify(collections));
  }, [collections]);

  // Close suggestions when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target as Node)) {
        setShowSearchSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Determine header text based on selection
  const activeCollection = collections.find(c => c.id === activeCategory);

  const activeCategoryData = useMemo(() => {
    if (activeCategory === 'saved') {
      return { id: 'saved', label: 'My Saved Templates', description: 'Your custom generated prompts' };
    }
    if (activeCollection) {
      return { id: activeCollection.id, label: activeCollection.name, description: 'Custom Collection' };
    }
    return CATEGORIES.find(c => c.id === activeCategory);
  }, [activeCategory, activeCollection]);

  const allPrompts = useMemo(() => {
    return [...savedPrompts, ...PROMPTS];
  }, [savedPrompts]);

  const uniqueFormats = useMemo(() => {
    const formats = new Set(allPrompts.map(p => p.format));
    return ['All', ...Array.from(formats)].sort();
  }, [allPrompts]);

  const filteredPrompts = useMemo(() => {
    return allPrompts.filter(prompt => {
      let matchesCategory = false;

      if (activeCategory === 'all') {
        matchesCategory = true;
      } else if (activeCategory === 'saved') {
        matchesCategory = prompt.categoryId === 'saved';
      } else if (activeCollection) {
        matchesCategory = prompt.collectionId === activeCategory;
      } else {
        matchesCategory = prompt.categoryId === activeCategory;
      }

      // Format Filter
      if (selectedFormat !== 'All' && prompt.format !== selectedFormat) {
        return false;
      }

      // Search Logic (Basic Fuzzy / Keyword)
      if (!searchQuery.trim()) return matchesCategory;

      const terms = searchQuery.toLowerCase().split(' ').filter(t => t.length > 0);
      const searchableText = `${prompt.title} ${prompt.bestFor} ${prompt.promptText} ${prompt.tags?.join(' ') || ''}`.toLowerCase();

      const matchesSearch = terms.every(term => searchableText.includes(term));

      return matchesCategory && matchesSearch;
    });
  }, [activeCategory, activeCollection, searchQuery, selectedFormat, allPrompts]);

  // Search Suggestions Logic
  const suggestions = useMemo(() => {
    if (!searchQuery.trim()) return [];
    const query = searchQuery.toLowerCase();

    const matchedTitles = allPrompts
      .filter(p => p.title.toLowerCase().includes(query))
      .map(p => ({ text: p.title, type: 'Title' }))
      .slice(0, 3);

    const matchedTags = Array.from(new Set(
      allPrompts.flatMap(p => p.tags || [])
        .filter(t => t.toLowerCase().includes(query))
    )).map(t => ({ text: t, type: 'Tag' }))
    .slice(0, 3);

    return [...matchedTitles, ...matchedTags];
  }, [searchQuery, allPrompts]);

  const handleQuickCopy = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleSaveCustomPrompt = (prompt: PromptData) => {
    setSavedPrompts(prev => [prompt, ...prev]);
    // Switch to the collection if one was assigned, otherwise saved view
    if (prompt.collectionId) {
      setActiveCategory(prompt.collectionId);
    } else {
      setActiveCategory('saved');
    }
    setCurrentView('library');
  };

  const handleUpdatePrompt = (updatedPrompt: PromptData) => {
    const isSaved = savedPrompts.some(p => p.id === updatedPrompt.id);
    if (isSaved) {
      setSavedPrompts(prev => prev.map(p => p.id === updatedPrompt.id ? updatedPrompt : p));
    } else {
      const newSavedPrompt = { ...updatedPrompt, categoryId: 'saved' };
      setSavedPrompts(prev => [newSavedPrompt, ...prev]);
    }
    setSelectedPrompt(updatedPrompt);
  };

  const handleCreateCollection = (name: string) => {
    const newCollection: Collection = {
      id: `col_${Date.now()}`,
      name,
      color: 'bg-blue-500',
      createdAt: Date.now()
    };
    setCollections(prev => [...prev, newCollection]);
    setActiveCategory(newCollection.id);
  };

  const handleDeleteCollection = (id: string) => {
    if (confirm('Are you sure you want to delete this collection? Prompts inside will remain in "Saved Templates".')) {
      setCollections(prev => prev.filter(c => c.id !== id));
      setSavedPrompts(prev => prev.map(p => p.collectionId === id ? { ...p, collectionId: undefined } : p));
      setActiveCategory('saved');
    }
  };

  const handleMovePrompt = (promptId: string, targetCollectionId: string) => {
    const promptToMove = allPrompts.find(p => p.id === promptId);
    if (!promptToMove) return;

    const isAlreadySaved = savedPrompts.some(p => p.id === promptId);

    if (isAlreadySaved) {
       setSavedPrompts(prev => prev.map(p => 
         p.id === promptId ? { ...p, collectionId: targetCollectionId } : p
       ));
    } else {
       const newPrompt = { 
         ...promptToMove, 
         categoryId: 'saved',
         collectionId: targetCollectionId,
         id: `saved_${promptToMove.id}_${Date.now()}` 
       };
       setSavedPrompts(prev => [...prev, newPrompt]);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex font-sans text-slate-900 overflow-hidden">
      <TutorialOverlay 
        isOpen={showTutorial} 
        onClose={() => {
          setShowTutorial(false);
          localStorage.setItem('tutorial_completed', 'true');
        }} 
      />

      <Sidebar 
        activeCategory={activeCategory} 
        onSelectCategory={setActiveCategory}
        collections={collections}
        onCreateCollection={handleCreateCollection}
        onDeleteCollection={handleDeleteCollection}
        isMobileOpen={isMobileSidebarOpen}
        setIsMobileOpen={setIsMobileSidebarOpen}
        currentView={currentView}
        onChangeView={setCurrentView}
        onOpenGenerator={() => setIsGeneratorOpen(true)}
        onMovePrompt={handleMovePrompt}
      />

      <main className="flex-1 flex flex-col h-screen overflow-hidden relative w-full">
        {/* Mobile Menu Button */}
        <button 
          className="md:hidden absolute top-4 left-4 z-40 p-2 bg-white/80 backdrop-blur shadow-sm border border-slate-200 rounded-lg text-slate-500"
          onClick={() => setIsMobileSidebarOpen(true)}
        >
          <Menu className="w-5 h-5" />
        </button>

        {currentView === 'library' ? (
          <>
            {/* Top Header */}
            <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shrink-0 pl-16 md:pl-6">
              <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 flex-1">

                {/* Search Bar Container */}
                <div className="relative w-full max-w-xl z-20" ref={searchContainerRef}>
                  <div className="flex gap-2">
                     <div className="relative flex-1">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-4 w-4 text-slate-400" />
                      </div>
                      <input
                        type="text"
                        className="block w-full pl-10 pr-3 py-2 border border-slate-200 rounded-xl leading-5 bg-slate-50 placeholder-slate-400 focus:outline-none focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 sm:text-sm transition-all"
                        placeholder="Search prompts..."
                        value={searchQuery}
                        onChange={(e) => {
                          setSearchQuery(e.target.value);
                          setShowSearchSuggestions(true);
                        }}
                        onFocus={() => setShowSearchSuggestions(true)}
                      />
                    </div>

                    {/* Format Filter Dropdown */}
                    <div className="relative">
                      <select
                        value={selectedFormat}
                        onChange={(e) => setSelectedFormat(e.target.value)}
                        className="appearance-none h-full bg-slate-50 border border-slate-200 rounded-xl pl-3 pr-8 py-2 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500 cursor-pointer hover:bg-white transition-colors"
                      >
                        {uniqueFormats.map(f => (
                          <option key={f} value={f}>{f === 'All' ? 'All Formats' : f}</option>
                        ))}
                      </select>
                      <Filter className="absolute right-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-400 pointer-events-none" />
                    </div>
                  </div>

                  {/* Search Suggestions Dropdown */}
                  {showSearchSuggestions && suggestions.length > 0 && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-xl shadow-lg border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-top-2">
                      <p className="px-4 py-2 text-[10px] font-semibold text-slate-400 uppercase tracking-wider bg-slate-50">Suggestions</p>
                      {suggestions.map((item, idx) => (
                        <button
                          key={idx}
                          className="w-full text-left px-4 py-2.5 text-sm text-slate-700 hover:bg-slate-50 flex items-center justify-between group transition-colors"
                          onClick={() => {
                            setSearchQuery(item.text);
                            setShowSearchSuggestions(false);
                          }}
                        >
                          <span>{item.text}</span>
                          <span className="text-[10px] text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded opacity-0 group-hover:opacity-100 transition-opacity">
                            {item.type}
                          </span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              </div>

              <div className="hidden sm:flex items-center gap-3">
                 <a 
                  href="https://notebooklm.google.com/" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-blue-600 transition-colors"
                 >
                   Open NotebookLM
                   <Sparkles className="w-4 h-4" />
                 </a>
              </div>
            </header>

            {/* Scrollable Content */}
            <div className="flex-1 overflow-y-auto p-6 md:p-8">
              <div className="max-w-6xl mx-auto">

                <div className="mb-8">
                  <div className="flex items-baseline gap-2">
                    <h2 className="text-2xl font-bold text-slate-900 mb-2">
                      {activeCategoryData?.label || 'Unknown Category'}
                    </h2>
                    {selectedFormat !== 'All' && (
                       <span className="text-sm font-medium text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">
                         {selectedFormat}
                       </span>
                    )}
                  </div>
                  <p className="text-slate-500">
                    {activeCategory === 'all' 
                      ? `${allPrompts.length}+ context-engineered prompts ready to copy.` 
                      : activeCategoryData?.description}
                  </p>
                </div>

                {filteredPrompts.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {filteredPrompts.map((prompt) => (
                      <PromptCard 
                        key={prompt.id} 
                        prompt={prompt}
                        onClick={() => setSelectedPrompt(prompt)}
                        onQuickCopy={(e, text) => handleQuickCopy(e, text, prompt.id)}
                        isCopied={copiedId === prompt.id}
                      />
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-20 bg-white rounded-2xl border border-dashed border-slate-300">
                    <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                    <h3 className="text-lg font-medium text-slate-900 mb-1">No prompts found</h3>
                    <p className="text-slate-500">Try adjusting your search terms or filters.</p>
                    {(activeCategory !== 'all' || selectedFormat !== 'All') && (
                      <button 
                        onClick={() => {
                          setActiveCategory('all');
                          setSelectedFormat('All');
                          setSearchQuery('');
                        }}
                        className="mt-4 text-blue-600 font-medium hover:underline"
                      >
                        Clear all filters
                      </button>
                    )}
                  </div>
                )}

                <footer className="mt-12 text-center text-xs text-slate-400 pb-4">
                  <p>Prompts designed using the R-I-S-E Framework (Role, Input, Stop, Example)</p>
                </footer>
              </div>
            </div>

            <PromptModal 
              prompt={selectedPrompt} 
              collections={collections}
              onUpdatePrompt={handleUpdatePrompt}
              onClose={() => setSelectedPrompt(null)} 
            />
          </>
        ) : (
          <Workbench />
        )}

        {/* Global Prompt Generator Modal */}
        <PromptGenerator 
          isOpen={isGeneratorOpen} 
          collections={collections}
          onClose={() => setIsGeneratorOpen(false)} 
          onSave={handleSaveCustomPrompt}
        />
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { X, Wand2, Copy, Check, RefreshCw, Save, Tag, Folder, MessageSquare } from 'lucide-react';
import { CATEGORIES } from '../constants';
import { PromptData, Collection } from '../types';

interface PromptGeneratorProps {
  isOpen: boolean;
  onClose: () => void;
  onSave?: (prompt: PromptData) => void;
  collections?: Collection[];
}

const PromptGenerator: React.FC<PromptGeneratorProps> = ({ isOpen, onClose, onSave, collections = [] }) => {
  const [topic, setTopic] = useState('');
  const [format, setFormat] = useState('Audio Overview');
  const [audience, setAudience] = useState('General Audience');
  const [tone, setTone] = useState('Professional');

  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPrompt, setGeneratedPrompt] = useState('');
  const [isCopied, setIsCopied] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  // Organization fields
  const [tags, setTags] = useState('');
  const [selectedCollectionId, setSelectedCollectionId] = useState('');

  if (!isOpen) return null;

  const handleGenerate = (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);

    // Simulate AI thinking time with slightly more complex logic
    setTimeout(() => {
      const prompt = `Act as an expert content creator specializing in ${format} for ${audience}.

Role: You are a ${tone} expert in ${topic}.
Input: Analyze the provided source materials related to ${topic}, extracting key information, themes, and data points.

Constraint: Stop at the provided context. Do not introduce external information or hallucinations outside of the source text. Maintain a ${tone.toLowerCase()} tone throughout.

Task: Deliver a ${format} that is strictly based on the source text, structured logically, and optimized for ${audience}.`;

      setGeneratedPrompt(prompt);
      setIsGenerating(false);
    }, 800);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(generatedPrompt);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const handleSaveToLibrary = () => {
    if (onSave) {
      const parsedTags = tags.split(',').map(t => t.trim()).filter(t => t.length > 0);

      const newPrompt: PromptData = {
        id: Math.random().toString(36).substr(2, 9),
        categoryId: 'saved',
        title: `${topic} (${format})`,
        format: format,
        bestFor: audience,
        promptText: generatedPrompt,
        exampleSources: 'User specified sources',
        tip: 'Generated via Prompt Generator',
        tags: parsedTags,
        collectionId: selectedCollectionId || undefined
      };
      onSave(newPrompt);
      setIsSaved(true);
      setTimeout(() => {
        setIsSaved(false);
        onClose();
      }, 1000);
    }
  };

  const handleReset = () => {
    setGeneratedPrompt('');
    setIsCopied(false);
    setIsSaved(false);
    setTags('');
    setSelectedCollectionId('');
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-lg overflow-hidden flex flex-col animate-in fade-in zoom-in-95 duration-200 border border-slate-100 max-h-[90vh] overflow-y-auto">
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-slate-100 bg-gradient-to-r from-purple-50 to-white sticky top-0 z-10">
          <div className="flex items-center gap-2">
            <div className="bg-purple-100 p-2 rounded-lg text-purple-600">
              <Wand2 className="w-5 h-5" />
            </div>
            <h2 className="text-lg font-bold text-slate-900">Prompt Generator</h2>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6">
          {!generatedPrompt ? (
            <form onSubmit={handleGenerate} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Topic or Source Material
                </label>
                <input
                  type="text"
                  required
                  placeholder="e.g., Quarterly Financial Report, The Great Gatsby"
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent transition-all"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Format
                  </label>
                  <select
                    value={format}
                    onChange={(e) => setFormat(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent bg-white"
                  >
                    {CATEGORIES.filter(c => c.id !== 'all').map(c => (
                      <option key={c.id} value={c.label}>{c.label}</option>
                    ))}
                    <option value="Custom Format">Custom Format</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">
                    Tone
                  </label>
                  <select
                    value={tone}
                    onChange={(e) => setTone(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent bg-white"
                  >
                    <option value="Professional">Professional</option>
                    <option value="Academic">Academic</option>
                    <option value="Casual">Casual</option>
                    <option value="Funny">Funny</option>
                    <option value="Persuasive">Persuasive</option>
                    <option value="Empathetic">Empathetic</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  Target Audience
                </label>
                <input
                  type="text"
                  placeholder="e.g., Beginners, Executives, Students"
                  value={audience}
                  onChange={(e) => setAudience(e.target.value)}
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                />
              </div>

              <div className="pt-2">
                <button
                  type="submit"
                  disabled={!topic || isGenerating}
                  className={`
                    w-full flex items-center justify-center gap-2 py-2.5 rounded-lg text-white font-medium transition-all
                    ${!topic || isGenerating 
                      ? 'bg-purple-300 cursor-not-allowed' 
                      : 'bg-purple-600 hover:bg-purple-700 shadow-md hover:shadow-lg'}
                  `}
                >
                  {isGenerating ? (
                    <>
                      <RefreshCw className="w-4 h-4 animate-spin" />
                      Generating...
                    </>
                  ) : (
                    <>
                      <Wand2 className="w-4 h-4" />
                      Generate Prompt
                    </>
                  )}
                </button>
              </div>

              <p className="text-center text-xs text-slate-400 mt-2">
                Uses the R-I-S-E framework to structure your prompt automatically.
              </p>
            </form>
          ) : (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2">
              <div className="bg-purple-50 border border-purple-100 rounded-xl p-4 relative">
                <div className="absolute top-3 right-3 flex gap-2">
                  <button
                    onClick={handleCopy}
                    className={`
                      p-1.5 rounded-md transition-all
                      ${isCopied ? 'bg-green-100 text-green-700' : 'bg-white text-slate-400 hover:text-purple-600 shadow-sm'}
                    `}
                    title="Copy to clipboard"
                  >
                    {isCopied ? <Check className="w-4 h-4" /> : <Copy className="w-4 h-4" />}
                  </button>
                </div>
                <h3 className="text-xs font-bold text-purple-800 uppercase tracking-wider mb-2">Generated Prompt</h3>
                <pre className="whitespace-pre-wrap font-sans text-slate-800 text-sm leading-relaxed pr-8">
                  {generatedPrompt}
                </pre>
              </div>

              {/* Organization Fields for Saving */}
              {onSave && (
                <div className="bg-slate-50 rounded-xl p-4 border border-slate-100 space-y-3">
                  <h4 className="text-xs font-semibold text-slate-500 uppercase">Organization</h4>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1 flex items-center gap-1">
                        <Tag className="w-3 h-3" /> Tags (comma separated)
                      </label>
                      <input
                        type="text"
                        value={tags}
                        onChange={(e) => setTags(e.target.value)}
                        placeholder="e.g., work, important, draft"
                        className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded-md focus:outline-none focus:ring-1 focus:ring-purple-500"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-medium text-slate-600 mb-1 flex items-center gap-1">
                        <Folder className="w-3 h-3" /> Collection
                      </label>
                      <select
                        value={selectedCollectionId}
                        onChange={(e) => setSelectedCollectionId(e.target.value)}
                        className="w-full px-2 py-1.5 text-sm border border-slate-200 rounded-md focus:outline-none focus:ring-1 focus:ring-purple-500 bg-white"
                      >
                        <option value="">None (Unsorted)</option>
                        {collections.map(col => (
                          <option key={col.id} value={col.id}>{col.name}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                </div>
              )}

              <div className="flex gap-3 pt-2">
                <button
                  onClick={handleReset}
                  className="px-4 py-2 border border-slate-200 rounded-lg text-slate-600 hover:bg-slate-50 text-sm font-medium transition-colors"
                >
                  Back
                </button>

                {onSave && (
                   <button
                    onClick={handleSaveToLibrary}
                    className={`
                      flex-1 flex items-center justify-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm
                      ${isSaved ? 'bg-green-600 text-white' : 'bg-white border border-slate-200 text-slate-700 hover:border-purple-300 hover:text-purple-600'}
                    `}
                  >
                    {isSaved ? <Check className="w-4 h-4" /> : <Save className="w-4 h-4" />}
                    {isSaved ? 'Saved!' : 'Save Template'}
                  </button>
                )}

                <button
                  onClick={() => {
                    handleCopy();
                    onClose();
                  }}
                  className="flex-1 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium transition-colors shadow-sm"
                >
                  Copy & Close
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

