        <span className="text-xs text-slate-400 font-medium group-hover:text-slate-600 transition-colors">Click to view details</span>
        <div className="bg-slate-50 p-1.5 rounded-full group-hover:bg-blue-600 group-hover:text-white transition-all duration-300">
          <ArrowRight className="w-4 h-4 text-slate-400 group-hover:text-white" />
        </div>
      </div>
    </div>
  );
};

export default PromptCard;

import React, { useState, useEffect } from 'react';
import { X, Copy, Check, Info, Lightbulb, Tag, Folder, Layers, FileText, LayoutTemplate } from 'lucide-react';
import { PromptData, Collection } from '../types';
import { CATEGORIES } from '../constants';

interface PromptModalProps {
  prompt: PromptData | null;
  collections?: Collection[];
  onUpdatePrompt?: (prompt: PromptData) => void;
  onClose: () => void;
}

const PromptModal: React.FC<PromptModalProps> = ({ prompt, collections = [], onUpdatePrompt, onClose }) => {
  const [isCopied, setIsCopied] = useState(false);
  const [tags, setTags] = useState<string>('');
  const [collectionId, setCollectionId] = useState<string>('');
  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    setIsCopied(false);
    if (prompt) {
      setTags(prompt.tags ? prompt.tags.join(', ') : '');
      setCollectionId(prompt.collectionId || '');
      setIsEditing(false);
    }
  }, [prompt]);

  if (!prompt) return null;

  const category = CATEGORIES.find(c => c.id === prompt.categoryId);

  const handleCopy = () => {
    navigator.clipboard.writeText(prompt.promptText);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const handleSaveOrganization = () => {
    if (onUpdatePrompt) {
      const parsedTags = tags.split(',').map(t => t.trim()).filter(t => t.length > 0);
      onUpdatePrompt({
        ...prompt,
        tags: parsedTags,
        collectionId: collectionId || undefined
      });
      setIsEditing(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      />

      <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col animate-in fade-in zoom-in-95 duration-200">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-slate-100 bg-white sticky top-0 z-10">
          <div>
            <h2 className="text-xl font-bold text-slate-900 leading-tight pr-8">
              {prompt.title}
            </h2>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors absolute top-4 right-4"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Content */}
        <div className="overflow-y-auto p-6 space-y-6">

          {/* Main Prompt Area */}
          <div className="bg-slate-50 border border-slate-200 rounded-xl p-5 relative group">
            <div className="absolute top-3 right-3">
              <button
                onClick={handleCopy}
                className={`
                  flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium transition-all shadow-sm
                  ${isCopied 
                    ? 'bg-green-600 text-white hover:bg-green-700' 
                    : 'bg-white text-slate-700 hover:bg-slate-50 border border-slate-200'}
                `}
              >
                {isCopied ? (
                  <>
                    <Check className="w-4 h-4" />
                    <span>Copied</span>
                  </>
                ) : (
                  <>
                    <Copy className="w-4 h-4" />
                    <span>Copy Prompt</span>
                  </>
                )}
              </button>
            </div>
            <pre className="whitespace-pre-wrap font-sans text-slate-800 text-sm leading-relaxed pt-8 sm:pt-0 sm:pr-24">
              {prompt.promptText}
            </pre>
          </div>

          {/* New Visually Distinct Metadata Panel */}
          <div className="bg-slate-100 rounded-xl p-5 border border-slate-200">
            <h4 className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-3">Key Metadata</h4>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="space-y-4">
                 <div>
                   <span className="text-[10px] text-slate-400 mb-1 block">Format</span>
                   <div className="flex items-center gap-2 text-slate-800 font-semibold text-sm">
                     <FileText className="w-4 h-4 text-blue-500" />
                     {prompt.format}
                   </div>
                 </div>
                 <div>
                   <span className="text-[10px] text-slate-400 mb-1 block">Category</span>
                   <div className="flex items-center gap-2 text-slate-800 font-semibold text-sm">
                     <Layers className="w-4 h-4 text-purple-500" />
                     {category?.label || 'General'}
                   </div>
                 </div>
              </div>

              <div>
                <span className="text-[10px] text-slate-400 mb-1 block flex items-center gap-1">
                  <Info className="w-3 h-3" /> Best For
                </span>
                <p className="text-sm text-slate-700 leading-relaxed font-medium">
                  {prompt.bestFor}
                </p>
              </div>
            </div>
          </div>

          {/* Organization Bar */}
          <div className="bg-white border border-slate-200 rounded-lg p-3">
             <div className="flex justify-between items-center mb-2">
               <h4 className="text-xs font-bold text-slate-500 uppercase">Organization</h4>
               {!isEditing && onUpdatePrompt && (
                 <button onClick={() => setIsEditing(true)} className="text-xs text-blue-600 font-medium hover:underline">
                   Edit
                 </button>
               )}
             </div>

             {isEditing ? (
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                 <div>
                   <label className="text-xs text-slate-400 block mb-1">Tags</label>
                   <input
                    type="text"
                    value={tags}
                    onChange={e => setTags(e.target.value)}
                    className="w-full text-sm border border-slate-200 rounded px-2 py-1"
                    placeholder="comma, separated"
                   />
                 </div>
                 <div>
                   <label className="text-xs text-slate-400 block mb-1">Collection</label>
                   <select
                    value={collectionId}
                    onChange={e => setCollectionId(e.target.value)}
                    className="w-full text-sm border border-slate-200 rounded px-2 py-1 bg-white"
                   >
                     <option value="">None</option>
                     {collections.map(c => (
                       <option key={c.id} value={c.id}>{c.name}</option>
                     ))}
                   </select>
                 </div>
                 <div className="sm:col-span-2 flex justify-end gap-2 mt-1">
                   <button onClick={() => setIsEditing(false)} className="text-xs px-2 py-1 text-slate-500">Cancel</button>
                   <button onClick={handleSaveOrganization} className="text-xs px-3 py-1 bg-blue-600 text-white rounded">Save Changes</button>
                 </div>
               </div>
             ) : (
               <div className="flex flex-wrap gap-4 text-sm text-slate-600">
                 <div className="flex items-center gap-2">
                   <Folder className="w-4 h-4 text-slate-400" />
                   {collections.find(c => c.id === prompt.collectionId)?.name || <span className="text-slate-400 italic">Unfiled</span>}
                 </div>
                 <div className="flex items-center gap-2">
                   <Tag className="w-4 h-4 text-slate-400" />
                   {prompt.tags && prompt.tags.length > 0 ? (
                     <div className="flex gap-1 flex-wrap">
                       {prompt.tags.map(tag => (
                         <span key={tag} className="bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded text-xs border border-slate-200">
                           {tag}
                         </span>
                       ))}
                     </div>
                   ) : (
                     <span className="text-slate-400 italic">No tags</span>
                   )}
                 </div>
               </div>
             )}
          </div>

          {/* Tip Section */}
          <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 flex gap-3">
             <div className="bg-amber-100 p-2 rounded-lg h-fit text-amber-600 shrink-0">
               <Lightbulb className="w-5 h-5" />
             </div>
             <div>
               <h4 className="text-amber-900 font-bold text-sm mb-1">NotebookLM Pro Tip</h4>
               <p className="text-sm text-amber-800 leading-relaxed">
                 {prompt.tip}
               </p>
             </div>
          </div>

           <div className="bg-blue-50 border border-blue-100 rounded-lg p-4">
              <h4 className="text-blue-900 font-semibold text-sm mb-1">Recommended Sources</h4>
              <p className="text-sm text-blue-700">
                {prompt.exampleSources}
              </p>
            </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
};

export default PromptModal;

import React, { useState } from 'react';
import { 
  Headphones, 
  Video, 
  BrainCircuit, 
  FileText, 
  Layers, 
  HelpCircle, 
  PieChart, 
  Presentation, 
  Table, 
  LayoutGrid,
  Sparkles,
  X,
  Wand2,
  Bookmark,
  Folder,
  Plus,
  Trash2,
  Edit2,
  Check
} from 'lucide-react';
import { CATEGORIES } from '../constants';
import { IconName, Collection } from '../types';

interface SidebarProps {
  activeCategory: string;
  onSelectCategory: (id: string) => void;
  collections: Collection[];
  onCreateCollection: (name: string) => void;
  onDeleteCollection: (id: string) => void;
  onRenameCollection: (id: string, newName: string) => void;
  isMobileOpen: boolean;
  setIsMobileOpen: (isOpen: boolean) => void;
  currentView: 'library' | 'workbench';
  onChangeView: (view: 'library' | 'workbench') => void;
  onOpenGenerator: () => void;
  onMovePrompt?: (promptId: string, collectionId: string) => void;
}

const getIcon = (name: IconName, className: string) => {
  const icons: Record<IconName, React.ReactNode> = {
    Headphones: <Headphones className={className} />,
    Video: <Video className={className} />,
    BrainCircuit: <BrainCircuit className={className} />,
    FileText: <FileText className={className} />,
    Layers: <Layers className={className} />,
    HelpCircle: <HelpCircle className={className} />,
    PieChart: <PieChart className={className} />,
    Presentation: <Presentation className={className} />,
    Table: <Table className={className} />,
    All: <LayoutGrid className={className} />,
    Sparkles: <Sparkles className={className} />,
  };
  return icons[name] || <LayoutGrid className={className} />;
};

const Sidebar: React.FC<SidebarProps> = ({ 
  activeCategory, 
  onSelectCategory, 
  collections,
  onCreateCollection,
  onDeleteCollection,
  onRenameCollection,
  isMobileOpen, 
  setIsMobileOpen,
  currentView,
  onChangeView,
  onOpenGenerator,
  onMovePrompt
}) => {
  const [isCreatingCollection, setIsCreatingCollection] = useState(false);
  const [newCollectionName, setNewCollectionName] = useState('');
  const [editingCollectionId, setEditingCollectionId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState('');
  const [dragOverId, setDragOverId] = useState<string | null>(null);

  const [showNewBadge, setShowNewBadge] = useState(() => {
    return !localStorage.getItem('workbench_badge_dismissed');
  });

  const handleSubmitCollection = (e: React.FormEvent) => {
    e.preventDefault();
    if (newCollectionName.trim()) {
      onCreateCollection(newCollectionName.trim());
      setNewCollectionName('');
      setIsCreatingCollection(false);
    }
  };

  const handleRenameSubmit = (id: string) => {
    if (editingName.trim()) {
      onRenameCollection(id, editingName.trim());
      setEditingCollectionId(null);
    }
  };

  const handleDragOver = (e: React.DragEvent, collectionId: string) => {
    e.preventDefault();
    setDragOverId(collectionId);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    setDragOverId(null);
  };

  const handleDrop = (e: React.DragEvent, collectionId: string) => {
    e.preventDefault();
    setDragOverId(null);
    const promptId = e.dataTransfer.getData('text/plain');
    if (promptId && onMovePrompt) {
      onMovePrompt(promptId, collectionId);
    }
  };

  const dismissBadge = (e: React.MouseEvent) => {
    e.stopPropagation();
    setShowNewBadge(false);
    localStorage.setItem('workbench_badge_dismissed', 'true');
  };

  return (
    <>
      <div 
        className={`fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-40 md:hidden transition-opacity duration-300 ease-in-out ${
          isMobileOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
        }`}
        onClick={() => setIsMobileOpen(false)}
      />

      <aside className={`
        fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 cubic-bezier(0.4, 0, 0.2, 1) shadow-2xl md:shadow-none
        md:translate-x-0 md:static md:w-64 md:block
        ${isMobileOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="p-6 h-full flex flex-col">
          <div className="flex items-center justify-between mb-8">
            <div 
              className="flex items-center gap-2 cursor-pointer group" 
              onClick={() => { 
                onChangeView('library'); 
                setIsMobileOpen(false); 
              }}
            >
              <div className="bg-gradient-to-br from-blue-500 to-indigo-600 p-2 rounded-lg group-hover:shadow-md transition-all duration-200">
                <BrainCircuit className="w-6 h-6 text-white" />
              </div>
              <div>
                <h1 className="font-bold text-xl text-slate-800 leading-tight">Prompt Lib</h1>
                <p className="text-xs text-slate-500 font-medium">for NotebookLM</p>
              </div>
            </div>

            <button 
              onClick={() => setIsMobileOpen(false)}
              className="md:hidden p-2 text-slate-400 hover:bg-slate-100 hover:text-slate-600 rounded-lg transition-colors"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="space-y-1 mb-8">
            <button
              onClick={() => {
                onChangeView('library');
                setIsMobileOpen(false);
              }}
              className={`
                w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200
                ${currentView === 'library' 
                  ? 'bg-blue-50 text-blue-700 shadow-sm ring-1 ring-blue-100' 
                  : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}
              `}
            >
              <LayoutGrid className={`w-4 h-4 ${currentView === 'library' ? 'text-blue-600' : 'text-slate-400'}`} />
              Library
            </button>
            <button
              onClick={() => {
                onChangeView('workbench');
                setIsMobileOpen(false);
              }}
              className={`
                w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 group
                ${currentView === 'workbench' 
                  ? 'bg-purple-50 text-purple-700 shadow-sm ring-1 ring-purple-100' 
                  : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}
              `}
            >
              <Sparkles className={`w-4 h-4 ${currentView === 'workbench' ? 'text-purple-600' : 'text-slate-400'}`} />
              Workbench 
              {showNewBadge && (
                <span className="text-[10px] bg-purple-100 text-purple-600 px-1.5 py-0.5 rounded-full ml-auto shadow-sm flex items-center gap-1 group-hover:bg-purple-200 transition-colors">
                  NEW
                  <span 
                    onClick={dismissBadge}
                    className="hover:bg-purple-300 rounded-full p-0.5 cursor-pointer"
                  >
                    <X className="w-2 h-2" />
                  </span>
                </span>
              )}
            </button>

            <button
              onClick={() => {
                onOpenGenerator();
                setIsMobileOpen(false);
              }}
              className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-all duration-200"
            >
              <Wand2 className="w-4 h-4 text-slate-400" />
              Prompt Generator
            </button>
          </div>

          {currentView === 'library' && (
            <div className="flex-1 overflow-y-auto scrollbar-hide space-y-1 animate-in fade-in slide-in-from-left-4 duration-300">
              <p className="px-3 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2">My Collection</p>
               <button
                  onClick={() => {
                    onSelectCategory('saved');
                    setIsMobileOpen(false);
                  }}
                  className={`
                    w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200
                    ${activeCategory === 'saved' 
                      ? 'bg-slate-100 text-slate-900' 
                      : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}
                  `}
                >
                  <Bookmark className={`w-4 h-4 ${activeCategory === 'saved' ? 'text-slate-600' : 'text-slate-400'}`} />
                  Saved Templates
                </button>

              <div className="mt-4 mb-4">
                <div className="flex items-center justify-between px-3 mb-2">
                  <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Collections</p>
                  <button 
                    onClick={() => setIsCreatingCollection(true)}
                    className="p-1 hover:bg-slate-100 rounded text-slate-400 hover:text-slate-600"
                  >
                    <Plus className="w-3.5 h-3.5" />
                  </button>
                </div>

                {isCreatingCollection && (
                  <form onSubmit={handleSubmitCollection} className="px-3 mb-2">
                    <input
                      type="text"
                      autoFocus
                      placeholder="Name..."
                      className="w-full text-xs px-2 py-1.5 border border-slate-300 rounded focus:border-blue-500 focus:outline-none"
                      value={newCollectionName}
                      onChange={(e) => setNewCollectionName(e.target.value)}
                      onBlur={() => !newCollectionName && setIsCreatingCollection(false)}
                    />
                  </form>
                )}

                {collections.map((collection) => (
                   <div 
                      key={collection.id} 
                      className={`
                        group flex items-center justify-between pr-2 rounded-lg transition-all
                        ${dragOverId === collection.id ? 'bg-blue-50 ring-2 ring-blue-300 scale-[1.02]' : ''}
                      `}
                      onDragOver={(e) => handleDragOver(e, collection.id)}
                      onDragLeave={handleDragLeave}
                      onDrop={(e) => handleDrop(e, collection.id)}
                   >
                     {editingCollectionId === collection.id ? (
                        <div className="flex-1 flex items-center gap-1 px-2 py-1">
                          <input
                            type="text"
                            autoFocus
                            value={editingName}
                            onChange={(e) => setEditingName(e.target.value)}
                            onBlur={() => handleRenameSubmit(collection.id)}
                            onKeyDown={(e) => e.key === 'Enter' && handleRenameSubmit(collection.id)}
                            className="flex-1 text-xs border border-blue-400 rounded px-1.5 py-1 outline-none"
                          />
                          <button onClick={() => handleRenameSubmit(collection.id)} className="p-1 text-green-600">
                            <Check className="w-3 h-3" />
                          </button>
                        </div>
                     ) : (
                        <>
                          <button
                            onClick={() => {
                              onSelectCategory(collection.id);
                              setIsMobileOpen(false);
                            }}
                            className={`
                              flex-1 flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-all duration-200 text-left truncate
                              ${activeCategory === collection.id 
                                ? 'bg-slate-100 text-slate-900' 
                                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}
                            `}
                          >
                            <Folder className={`w-4 h-4 flex-shrink-0 ${activeCategory === collection.id ? 'fill-blue-100 text-blue-600' : 'fill-slate-50 text-slate-400'}`} />
                            <span className="truncate">{collection.name}</span>
                          </button>
                          <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                setEditingCollectionId(collection.id);
                                setEditingName(collection.name);
                              }}
                              className="p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded transition-all"
                            >
                              <Edit2 className="w-3.5 h-3.5" />
                            </button>
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                onDeleteCollection(collection.id);
                              }}
                              className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded transition-all"
                            >
                              <Trash2 className="w-3.5 h-3.5" />
                            </button>
                          </div>
                        </>
                     )}
                   </div>
                ))}
              </div>

              <p className="px-3 text-xs font-semibold text-slate-400 uppercase tracking-wider mb-2 mt-6">Categories</p>
              {CATEGORIES.filter(c => c.id !== 'all').map((category) => {
                const isActive = activeCategory === category.id;
                return (
                  <button
                    key={category.id}
                    onClick={() => {
                      onSelectCategory(category.id);
                      setIsMobileOpen(false);
                    }}
                    className={`
                      w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all duration-200
                      ${isActive 
                        ? 'bg-slate-100 text-slate-900' 
                        : 'text-slate-500 hover:bg-slate-50 hover:text-slate-700'}
                    `}
                  >
                    {getIcon(category.iconName as IconName, `w-4 h-4 ${isActive ? 'text-slate-600' : 'text-slate-400'}`)}
                    {category.label}
                  </button>
                );
              })}
            </div>
          )}

          {currentView === 'workbench' && (
             <div className="flex-1 overflow-y-auto scrollbar-hide space-y-4 px-3 animate-in fade-in slide-in-from-left-4 duration-300">
               <div className="bg-purple-50 rounded-lg p-3 border border-purple-100">
                 <h4 className="text-xs font-bold text-purple-800 mb-1">Collaborative Mode</h4>
                 <p className="text-xs text-purple-600 leading-relaxed mb-3">
                   Mock environment to test prompts with simulated real-time editing and citation tools.
                 </p>

                 <div className="text-[10px] text-purple-700 font-medium bg-purple-100/50 p-2 rounded border border-purple-200 space-y-1">
                   <p className="font-bold text-purple-800">Shortcuts</p>
                   <div className="flex justify-between"><span>Save</span> <span>Cmd + S</span></div>
                   <div className="flex justify-between"><span>Undo</span> <span>Cmd + Z</span></div>
                   <div className="flex justify-between"><span>Redo</span> <span>Cmd + Shift + Z</span></div>
                   <div className="flex justify-between"><span>Toggle Preview</span> <span>Cmd + I</span></div>
                 </div>
               </div>
             </div>
          )}

          <div className="mt-8 pt-6 border-t border-slate-100">
            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
              <h3 className="font-semibold text-slate-800 text-sm mb-1">R-I-S-E Framework</h3>
              <ul className="text-xs text-slate-500 space-y-1">
                <li><strong className="text-slate-700">R</strong>ole: Who AI acts as</li>
                <li><strong className="text-slate-700">I</strong>nput: Sources to use</li>
                <li><strong className="text-slate-700">S</strong>top: Boundaries</li>
                <li><strong className="text-slate-700">E</strong>xample: Output format</li>
              </ul>
            </div>
          </div>
        </div>
      </aside>
