              </div>

              <div>
                <span className="text-[10px] text-slate-400 mb-1 block flex items-center gap-1">
                  <Info className="w-3 h-3" /> Best For
                </span>
                <p className="text-sm text-slate-700 leading-relaxed font-medium">
                  {prompt.bestFor}
