const CACHE_NAME = 'notebooklm-v1.0.4';
const STATIC_ASSETS = [
  './',
  'index.html',
  'manifest.json',
  'metadata.json',
  'offline.html'
];

const CDN_DOMAINS = [
  'esm.sh',
  'cdn.tailwindcss.com',
  'fonts.googleapis.com',
  'fonts.gstatic.com'
];

self.addEventListener('install', (event) => {
  self.skipWaiting();
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(STATIC_ASSETS);
    })
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.map((key) => {
          if (key !== CACHE_NAME) {
            return caches.delete(key);
          }
        })
      );
    })
  );
  return self.clients.claim();
});

self.addEventListener('fetch', (event) => {
  const url = new URL(event.request.url);

  // Strategy 1: Stale-While-Revalidate for local assets
  const isStaticAsset = STATIC_ASSETS.some(asset => {
    const normalizedAsset = asset.startsWith('./') ? asset.slice(2) : asset;
    return url.pathname.endsWith(normalizedAsset) || (normalizedAsset === '' && url.pathname.endsWith('/'));
  });

  if (isStaticAsset) {
    event.respondWith(staleWhileRevalidate(event.request));
    return;
  }

  // Strategy 2: Navigation Fallback for Offline Support
  // This explicitly catches navigation errors to serve the offline page
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => {
        return caches.match('offline.html') || caches.match('./offline.html');
      })
    );
    return;
  }

  // Strategy 3: Cache-First for CDNs (with version persistence)
  if (CDN_DOMAINS.some(domain => url.hostname.includes(domain))) {
    event.respondWith(cacheFirst(event.request));
    return;
  }

  // Default: Network with fallback to cache
  event.respondWith(
    fetch(event.request).catch(() => caches.match(event.request))
  );
});

async function staleWhileRevalidate(request) {
  const cache = await caches.open(CACHE_NAME);
  const cachedResponse = await cache.match(request);
  const networkPromise = fetch(request).then((networkResponse) => {
    if (networkResponse.ok && request.method === 'GET') {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  }).catch(() => cachedResponse);

  return cachedResponse || networkPromise;
}

async function cacheFirst(request) {
  const cachedResponse = await caches.match(request);
  if (cachedResponse) return cachedResponse;

  try {
    const networkResponse = await fetch(request);
    const cache = await caches.open(CACHE_NAME);
    if (networkResponse.ok && request.method === 'GET') {
      cache.put(request, networkResponse.clone());
    }
    return networkResponse;
  } catch (err) {
    return cachedResponse;
  }
}

import React, { useState } from 'react';
import { 
  Headphones, 
  Video, 
  BrainCircuit, 
  FileText, 
  Layers, 
  HelpCircle, 
  PieChart, 
  Presentation, 
  Table, 
  LayoutGrid,
  Sparkles,
  X,
  Wand2,
  Bookmark,
  Folder,
  Plus,
  Trash2,
  Edit2,
  Check
} from 'lucide-react';
import { CATEGORIES } from '../constants.ts';
import { IconName, Collection } from '../types.ts';

interface SidebarProps {
  activeCategory: string;
  onSelectCategory: (id: string) => void;
  collections: Collection[];
  onCreateCollection: (name: string) => void;
  onDeleteCollection: (id: string) => void;
  onRenameCollection: (id: string, newName: string) => void;
  isMobileOpen: boolean;
  setIsMobileOpen: (isOpen: boolean) => void;
  currentView: 'library' | 'workbench';
  onChangeView: (view: 'library' | 'workbench') => void;
  onOpenGenerator: () => void;
  onMovePrompt?: (promptId: string, collectionId: string) => void;
}

const getIcon = (name: IconName, className: string) => {
  const icons: Record<IconName, React.ReactNode> = {
    Headphones: <Headphones className={className} />,
    Video: <Video className={className} />,
    BrainCircuit: <BrainCircuit className={className} />,
    FileText: <FileText className={className} />,
    Layers: <Layers className={className} />,
    HelpCircle: <HelpCircle className={className} />,
    PieChart: <PieChart className={className} />,
    Presentation: <Presentation className={className} />,
    Table: <Table className={className} />,
    All: <LayoutGrid className={className} />,
    Sparkles: <Sparkles className={className} />,
  };
  return icons[name] || <LayoutGrid className={className} />;
};

const Sidebar: React.FC<SidebarProps> = ({ 
  activeCategory, 
  onSelectCategory, 
  collections,
  onCreateCollection,
  onDeleteCollection,
  onRenameCollection,
  isMobileOpen, 
  setIsMobileOpen,
  currentView,
  onChangeView,
